                timestamp: new Date().toLocaleString(),
                details: details,
                message: details 
            };

            emailJS.send(EMAILJS_CONFIG.SERVICE_ID, EMAILJS_CONFIG.LOG_TEMPLATE_ID, templateParams, EMAILJS_CONFIG.PUBLIC_KEY)
                .then((response: any) => {
