                .catch((error: any) => {
                    console.error("EmailJS Error:", error);
                    // Silent fail for logging emails to avoid disrupting user
                });
          }

      } catch (error) {
          console.error("Error logging action:", error);
      }
  }, [currentUser]);


  const handleLogout = useCallback(() => handleAction(async () => {
    await signOut(auth);
  }), [handleAction]);

  const logoutDueToInactivity = useCallback(() => {
    handleLogout();
    addToast('Session Expired', 'You have been logged out due to inactivity.', 'info');
  }, [handleLogout, addToast]);

  // Effect for inactivity timer
  useEffect(() => {
    if (currentUser) {
        const resetTimer = () => {
            if (inactivityTimer.current) window.clearTimeout(inactivityTimer.current);
            inactivityTimer.current = window.setTimeout(logoutDueToInactivity, 5 * 60 * 1000); // 5 minutes
        };

        const events = ['mousedown', 'keypress', 'scroll', 'touchstart', 'click'];
        resetTimer(); 
        events.forEach(event => window.addEventListener(event, resetTimer));

        return () => {
            if (inactivityTimer.current) window.clearTimeout(inactivityTimer.current);
            events.forEach(event => window.removeEventListener(event, resetTimer));
        };
    }
  }, [currentUser, logoutDueToInactivity]);

  // Global Settings Listener
  useEffect(() => {
      const settingsRef = doc(firestoreDb, 'settings', 'main');
      const unsubscribeSettings = onSnapshot(settingsRef, (docSnap) => {
          if (docSnap.exists()) {
              const data = docSnap.data();
              setAppLogo(data.appLogo || null);
