const StatCard = ({ icon, title, value, color }: { icon: React.ReactNode, title: string, value: number, color: string }) => (
  <div className="bg-white p-6 rounded-xl flex items-center space-x-4 shadow-sm border border-gray-200">
    <div className={`p-3 rounded-full ${color}`}>
      {icon}
    </div>
    <div>
      <p className="text-gray-500 text-sm">{title}</p>
      <p className="text-2xl font-bold text-brand-text">{value}</p>
    </div>
  </div>
);

interface DashboardProps {
    contacts: Contact[];
    rentals: Rental[];
    repairs: Repair[];
    users: User[];
    currentUser: User;
    siteContacts: SiteContact[];
    siteRentals: SiteRental[];
    siteRepairs: SiteRepair[];
}

const Dashboard: React.FC<DashboardProps> = ({ contacts, rentals, repairs, users, currentUser, siteContacts, siteRentals, siteRepairs }) => {
  const activeRentals = rentals.filter(r => r.status === 'Active').length;
  const openRepairs = repairs.filter(r => r.status === 'Open' || r.status === 'In Progress').length;

  const pendingSiteSubmissions = [
      ...siteContacts.filter(s => s.status !== 'completed'),
      ...siteRentals.filter(s => s.status !== 'completed'),
      ...siteRepairs.filter(s => s.status !== 'completed'),
  ];

  return (
    <div className="p-4 sm:p-8 text-brand-text">
       <div className="mb-8">
        <h1 className="text-3xl font-bold">SpinCity Command Center</h1>
        <p className="text-gray-500 mt-1">Hello, {currentUser.name}. Here is your business status today.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard icon={<ContactsIcon className="w-6 h-6 text-white"/>} title="Total Clients" value={contacts.length} color="bg-brand-green"/>
        <StatCard icon={<RentalsIcon className="w-6 h-6 text-white"/>} title="Active Rentals" value={activeRentals} color="bg-blue-500"/>
        <StatCard icon={<RepairsIcon className="w-6 h-6 text-white"/>} title="Open Repairs" value={openRepairs} color="bg-yellow-500"/>
        <StatCard icon={<UsersIcon className="w-6 h-6 text-white"/>} title="Pending Site Tasks" value={pendingSiteSubmissions.length} color="bg-red-500"/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
              <h2 className="text-xl font-bold mb-4 flex items-center">
                  <span className="w-2 h-2 bg-red-500 rounded-full mr-2"></span>
                  Action Required: Site Submissions
              </h2>
              {pendingSiteSubmissions.length > 0 ? (
                  <ul className="divide-y divide-gray-100">
                      {pendingSiteSubmissions.slice(0, 5).map((item, idx) => (
                          <li key={idx} className="py-3 flex justify-between items-center">
                              <div>
                                  <p className="font-semibold capitalize text-sm">{item.type}: {(item as any).name || (item as any).renter_name || (item as any).customerName}</p>
                                  <p className="text-xs text-gray-500">{(item as any).timestamp || (item as any).submissionDate}</p>
                              </div>
                              <span className="text-xs font-bold text-red-500 bg-red-50 px-2 py-1 rounded">New</span>
                          </li>
                      ))}
                  </ul>
              ) : (
                  <p className="text-gray-400 text-sm text-center py-8">Inbox is clear. Good job!</p>
              )}
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
              <h2 className="text-xl font-bold mb-4">Quick Insights</h2>
              <div className="space-y-4">
                  <div className="p-4 bg-lime-50 rounded-lg border border-lime-200">
                      <p className="text-sm font-semibold text-lime-800">Growth</p>
                      <p className="text-xs text-lime-700">You have added {contacts.filter(c => new Date(c.createdAt).getMonth() === new Date().getMonth()).length} new clients this month.</p>
                  </div>
                  <div className="p-4 bg-blue-50 rounded-lg border border-blue-200">
                      <p className="text-sm font-semibold text-blue-800">Fleet Status</p>
                      <p className="text-xs text-blue-700">{activeRentals} out of your machines are currently generating revenue.</p>
